pub struct Jit {
    pub symbols: HashMap<String, *const u8>,
}

impl Jit {
    pub fn new() -> Self {
        Self { symbols: HashMap::new() }
    }

    pub fn symbol(&mut self, name: impl Into<String>, ptr: *const u8) {
        self.symbols.insert(name.into(), ptr);
    }

    /// Compile a wire-format buffer and return an Artifact.
    /// Compile a wire-format buffer. (tape path not yet migrated)
    pub fn compile_tape(&self, _tape: &str) -> Result<Artifact, LalinError> {
        Err(LalinError("tape compiler not yet migrated; use binary wire format".into()))
    }

    /// Compile a wire-format buffer and return an Artifact.
    pub fn compile_binary(&self, payload: &[u8]) -> Result<Artifact, LalinError> {
        let isa = host_isa(false)?;
        let mut builder = JITBuilder::with_isa(isa, default_libcall_names());
        for (name, ptr) in &self.symbols {
            builder.symbol(name, *ptr);
        }
        let mut module = JITModule::new(builder);

        let result = decode::decode_module(payload, &mut module)?;
        module.finalize_definitions()
            .map_err(|e| LalinError(format!("failed to finalize JIT module: {e:?}")))?;

        let mut function_ptrs = HashMap::new();
        for (_wire_id, (func_id, name)) in &result.func_table {
            let ptr = module.get_finalized_function(*func_id);
            function_ptrs.insert(name.clone(), ptr);
        }

        Ok(Artifact {
            _module: module,
            function_ptrs,
        })
    }
}

impl Default for Jit {
    fn default() -> Self { Self::new() }
}

