pub struct Artifact {
    _module: JITModule,
    function_ptrs: HashMap<String, *const u8>,
}

impl Artifact {
    pub fn getpointer_by_name(&self, name: &str) -> Result<*const c_void, LalinError> {
        let ptr = self.function_ptrs.get(name).copied()
            .ok_or_else(|| LalinError(format!("unknown compiled function '{name}'")))?;
        Ok(ptr.cast())
    }

    pub fn free(self) {}
}

