// Host ISA
// ═══════════════════════════════════════════════════════════════════════════

fn build_host_isa(is_pic: bool) -> Result<Arc<dyn cranelift_codegen::isa::TargetIsa>, LalinError> {
    let mut flag_builder = settings::builder();
    flag_builder
        .set("use_colocated_libcalls", "false")
        .map_err(|e| LalinError(format!("failed to set Cranelift flag use_colocated_libcalls: {e}")))?;
    flag_builder
        .set("is_pic", if is_pic { "true" } else { "false" })
        .map_err(|e| LalinError(format!("failed to set Cranelift flag is_pic: {e}")))?;
    flag_builder
        .set("opt_level", "speed")
        .map_err(|e| LalinError(format!("failed to set Cranelift flag opt_level: {e}")))?;
    let isa_builder = cranelift_native::builder()
        .map_err(|e| LalinError(format!("host machine is not supported by Cranelift: {e}")))?;
    isa_builder
        .finish(settings::Flags::new(flag_builder))
        .map_err(|e| LalinError(format!("failed to finalize Cranelift ISA: {e}")))
}

fn host_isa(is_pic: bool) -> Result<Arc<dyn cranelift_codegen::isa::TargetIsa>, LalinError> {
    static JIT_ISA: OnceLock<Arc<dyn cranelift_codegen::isa::TargetIsa>> = OnceLock::new();
    static PIC_ISA: OnceLock<Arc<dyn cranelift_codegen::isa::TargetIsa>> = OnceLock::new();
    let slot = if is_pic { &PIC_ISA } else { &JIT_ISA };
    if let Some(isa) = slot.get() {
        return Ok(Arc::clone(isa));
    }
    let isa = build_host_isa(is_pic)?;
    let _ = slot.set(Arc::clone(&isa));
    Ok(isa)
}

pub fn align_to_shift(align: u32) -> Result<u8, LalinError> {
    if align == 0 {
        return Err(LalinError("stack slot alignment must be >= 1 byte".into()));
    }
    if !align.is_power_of_two() {
        return Err(LalinError(format!("stack slot alignment {align} is not a power of two")));
    }
    Ok(align.trailing_zeros() as u8)
}

