use crate::decode;
use crate::host_arena::{LalinHostFieldInit, LalinHostPtr, LalinHostRef};
use crate::{Artifact, Jit, LalinError, ObjectArtifact, compile_object_binary};
use std::cell::RefCell;
use std::ffi::{CStr, CString, c_char, c_int, c_void};
use std::ptr;

#[repr(C)]
pub struct lalin_jit_t {
    inner: Jit,
}

#[repr(C)]
pub struct lalin_artifact_t {
    inner: Artifact,
}

#[repr(C)]
pub struct lalin_bytes_t {
    data: *mut u8,
    len: usize,
}

thread_local! {
    static LAST_ERROR: RefCell<CString> = RefCell::new(CString::new("ok").expect("valid CString"));
}

fn set_last_error(message: impl Into<String>) {
    let mut text = message.into();
    if text.as_bytes().contains(&0) {
        text = text.replace('\0', "?");
    }
    LAST_ERROR.with(|slot| {
        *slot.borrow_mut() = CString::new(text).unwrap_or_else(|_| CString::new("lalin ffi error").unwrap());
    });
}

fn clear_last_error() {
    set_last_error("ok");
}

fn ok_int() -> c_int {
    clear_last_error();
    1
}

fn fail_int(msg: String) -> c_int {
    set_last_error(msg);
    0
}

fn fail_ptr(msg: String) -> *mut c_void {
    set_last_error(msg);
    ptr::null_mut()
}

fn fail_const_ptr(msg: String) -> *const c_void {
    set_last_error(msg);
    ptr::null()
}

fn require_ptr<'a, T>(ptr: *const T, name: &str) -> Result<&'a T, LalinError> {
    unsafe { ptr.as_ref() }
        .ok_or_else(|| LalinError(format!("{name} pointer was null")))
}

fn read_cstr<'a>(ptr: *const c_char, name: &str) -> Result<String, LalinError> {
    unsafe { CStr::from_ptr(ptr) }
        .to_str()
        .map(|s| s.to_owned())
        .map_err(|e| LalinError(format!("{name} is not valid UTF-8: {e}")))
}

// =========================================================================
// C API: JIT
// =========================================================================

#[unsafe(no_mangle)]
pub extern "C" fn lalin_last_error_message() -> *const c_char {
    LAST_ERROR.with(|slot| {
        let s = slot.borrow();
        s.as_ptr()
    })
}

#[unsafe(no_mangle)]
pub extern "C" fn lalin_jit_new() -> *mut lalin_jit_t {
    clear_last_error();
    let jit = Box::new(lalin_jit_t {
        inner: Jit::new(),
    });
    Box::into_raw(jit)
}

#[unsafe(no_mangle)]
pub extern "C" fn lalin_jit_free(jit: *mut lalin_jit_t) {
    if !jit.is_null() {
        clear_last_error();
        unsafe { drop(Box::from_raw(jit)); }
    }
}

#[unsafe(no_mangle)]
pub extern "C" fn lalin_jit_symbol(
    jit: *mut lalin_jit_t,
    name: *const c_char,
    ptr: *const u8,
) -> c_int {
    let result: Result<_, LalinError> = (|| {
        let jit = unsafe { (jit as *mut lalin_jit_t).as_mut() }
            .ok_or_else(|| LalinError("lalin_jit_t pointer was null".to_string()))?;
        let name = read_cstr(name, "symbol name")?;
        jit.inner.symbol(&name, ptr);
        Ok(())
    })();
    match result {
        Ok(()) => ok_int(),
        Err(err) => fail_int(err.0),
    }
}

#[unsafe(no_mangle)]
pub extern "C" fn lalin_artifact_free(artifact: *mut lalin_artifact_t) {
    if !artifact.is_null() {
        clear_last_error();
        unsafe { drop(Box::from_raw(artifact)); }
    }
}

#[unsafe(no_mangle)]
pub extern "C" fn lalin_jit_compile_binary(
    jit: *mut lalin_jit_t,
    data: *const u8,
    len: usize,
) -> *mut c_void {
    let result: Result<_, LalinError> = (|| {
        let jit = require_ptr(jit, "lalin_jit_t")?;
        if data.is_null() {
            return Err(LalinError("binary data pointer was null".to_string()));
        }
        let buf = unsafe { std::slice::from_raw_parts(data, len) };
        let artifact = jit.inner.compile_binary(buf)?;
        Ok(Box::into_raw(Box::new(lalin_artifact_t { inner: artifact })) as *mut c_void)
    })();
    match result {
        Ok(ptr) => { clear_last_error(); ptr }
        Err(err) => fail_ptr(err.0),
    }
}

#[unsafe(no_mangle)]
pub extern "C" fn lalin_artifact_getpointer(
    artifact: *mut lalin_artifact_t,
    func: *const c_char,
) -> *const c_void {
    let result: Result<_, LalinError> = (|| {
        let artifact = unsafe { artifact.as_ref() }
            .ok_or_else(|| LalinError("lalin_artifact_t pointer was null".to_string()))?;
        let func = read_cstr(func, "function id")?;
        artifact.inner.getpointer_by_name(&func)
    })();
    match result {
        Ok(ptr) => {
            clear_last_error();
            ptr
        }
        Err(err) => fail_const_ptr(err.0),
    }
}

// =========================================================================
// C API: Object emission
// =========================================================================

#[unsafe(no_mangle)]
pub extern "C" fn lalin_object_compile_binary(
    data: *const u8,
    len: usize,
    module_name: *const c_char,
    out: *mut lalin_bytes_t,
) -> c_int {
    let result: Result<_, LalinError> = (|| {
        let out = unsafe { out.as_mut() }
            .ok_or_else(|| LalinError("lalin_bytes_t output pointer was null".to_string()))?;
        if data.is_null() {
            return Err(LalinError("binary data pointer was null".to_string()));
        }
        let buf = unsafe { std::slice::from_raw_parts(data, len) };
        let module_name = if module_name.is_null() {
            "lalin_object".to_string()
        } else {
            read_cstr(module_name, "object module name")?
        };
        let artifact = compile_object_binary(buf, &module_name)?;
        let mut bytes = artifact.into_bytes().into_boxed_slice();
        out.data = bytes.as_mut_ptr();
        out.len = bytes.len();
        std::mem::forget(bytes);
        Ok(())
    })();
    match result {
        Ok(()) => ok_int(),
        Err(err) => fail_int(err.0),
    }
}

#[unsafe(no_mangle)]
pub extern "C" fn lalin_bytes_free(bytes: *mut lalin_bytes_t) {
    if !bytes.is_null() {
        clear_last_error();
        let b = unsafe { Box::from_raw(bytes) };
        if !b.data.is_null() && b.len > 0 {
            unsafe { drop(Vec::from_raw_parts(b.data, b.len, b.len)); }
        }
    }
}

local M = {}

function M.Define(T)
    local Back = T.LalinBack or T.LalinBack
    assert(Back, "lalin.back_program.Define expects LalinBack/LalinBack in the context")

    local api = {}

    local function copy_cmds(cmds)
        local out = {}
        for i = 1, #(cmds or {}) do out[#out + 1] = cmds[i] end
        return out
    end

    function api.empty()
        return Back.BackProgram({})
    end

    function api.program(cmds)
        return Back.BackProgram(copy_cmds(cmds))
    end

    function api.singleton(cmd)
        return Back.BackProgram({ cmd })
    end

    function api.concat(programs)
        local out = {}
        for i = 1, #(programs or {}) do
            local program = programs[i]
            for j = 1, #program.cmds do out[#out + 1] = program.cmds[j] end
        end
        return Back.BackProgram(out)
    end

    function api.append(program, cmd)
        local out = copy_cmds(program.cmds)
        out[#out + 1] = cmd
        return Back.BackProgram(out)
    end

    function api.extend(program, cmds)
        local out = copy_cmds(program.cmds)
        for i = 1, #(cmds or {}) do out[#out + 1] = cmds[i] end
        return Back.BackProgram(out)
    end

    function api.cmds(program)
        return copy_cmds(program.cmds)
    end

    return api
end

return M

